/* Questões autorais (nível ENARE), estilo equilibrado. */
window.BANK_EXTRA = [{"tema": "SUS/História", "q": "A Lei Eloy Chaves (1923) é considerada o marco inicial da previdência social no Brasil porque criou", "ops": ["o Ministério da Saúde, separando-o da Educação.", "o Instituto Nacional de Previdência Social (INPS), unificando a previdência.", "o Instituto Nacional de Assistência Médica da Previdência Social (INAMPS).", "as Caixas de Aposentadorias e Pensões (CAPs), organizadas por empresa e geridas pelo setor privado.", "os Institutos de Aposentadorias e Pensões (IAPs), organizados por categoria profissional."], "correct": 3, "c": "A Lei Eloy Chaves (1923) criou as CAPs — por empresa, privadas, iniciando pelos ferroviários. Os IAPs (por categoria) vieram na Era Vargas; INPS em 1966; INAMPS em 1977."}, {"tema": "SUS/História", "q": "A 8ª Conferência Nacional de Saúde (1986) é o grande marco da Reforma Sanitária porque", "ops": ["criou oficialmente o Sistema Único de Saúde por meio de lei ordinária.", "restringiu a participação social à esfera federal.", "extinguiu o INAMPS e transferiu seus recursos aos municípios.", "instituiu as Leis Orgânicas da Saúde nº 8.080 e nº 8.142.", "consolidou o conceito ampliado de saúde e serviu de base para o capítulo da saúde na Constituição de 1988."], "correct": 4, "c": "A 8ª CNS (Arouca) foi a 1ª aberta à sociedade, consolidou o conceito ampliado de saúde e originou a Comissão Nacional da Reforma Sanitária, base da CF/88. O SUS foi criado pela CF/88."}, {"tema": "SUS/Legislação", "q": "Sobre as Leis Orgânicas da Saúde, é correto afirmar que a Lei nº 8.142/1990", "ops": ["cria a Agência Nacional de Vigilância Sanitária (ANVISA).", "regulamenta a Lei 8.080 quanto às regiões de saúde, RAS, RENASES e RENAME.", "define os percentuais mínimos de aplicação em saúde pelos entes federativos.", "dispõe sobre a participação da comunidade (conselhos e conferências) e as transferências intergovernamentais de recursos.", "organiza o funcionamento do SUS, definindo princípios, diretrizes e competências das esferas."], "correct": 3, "c": "A 8.080 = organização/funcionamento; a 8.142 = participação social + repasse (supriu os vetos da 8.080). Decreto 7.508/2011 trata de regiões/RAS/RENASES/RENAME; LC 141/2012 dos percentuais."}, {"tema": "SUS/Legislação", "q": "O Decreto nº 7.508/2011, que regulamenta a Lei 8.080, instituiu como instrumento de pactuação entre os entes federativos na Região de Saúde o", "ops": ["Pacto pela Saúde, em suas dimensões pela Vida, em Defesa do SUS e de Gestão.", "Contrato Organizativo da Ação Pública da Saúde (COAP).", "Fundo Nacional de Saúde (FNS), responsável pelos repasses fundo a fundo.", "Sistema de Planejamento do SUS (PlanejaSUS).", "Colegiado de Gestão Regional (CGR)."], "correct": 1, "c": "O COAP é o acordo de colaboração entre os entes para organizar e integrar as ações na Região de Saúde, com metas e responsabilidades. É o conceito mais cobrado do Decreto 7.508/2011."}, {"tema": "SUS/Princípios", "q": "No SUS, o princípio doutrinário que preconiza tratar desigualmente os desiguais, alocando mais recursos a quem tem maior necessidade, é a", "ops": ["descentralização.", "universalidade.", "equidade.", "integralidade.", "hierarquização."], "correct": 2, "c": "Equidade = tratar desigualmente os desiguais (mais a quem mais precisa), combatendo iniquidades. Universalidade = direito de todos; integralidade = promoção à recuperação; descentralização/hierarquização são organizativos."}, {"tema": "SUS/Controle social", "q": "Quanto ao Conselho de Saúde (Lei 8.142/1990), é correto afirmar que ele é", "ops": ["composto majoritariamente por gestores e prestadores de serviços.", "responsável por pactuar consensualmente a gestão entre os entes federativos.", "um evento periódico, realizado a cada quatro anos, de caráter apenas consultivo.", "de existência facultativa nos municípios de pequeno porte.", "permanente e deliberativo, com composição paritária de 50% de usuários."], "correct": 4, "c": "O Conselho é permanente, deliberativo e paritário (50% usuários; 50% trabalhadores+gestores+prestadores). A Conferência é que ocorre a cada 4 anos. Pactuação entre gestores é papel das comissões intergestores (CIT/CIB/CIR)."}, {"tema": "SUS/RAS", "q": "Nas Redes de Atenção à Saúde (RAS), a Atenção Primária à Saúde é descrita como", "ops": ["a base inferior de uma pirâmide de complexidade crescente.", "um sistema de apoio logístico da rede, como o transporte sanitário.", "um ponto de atenção secundária de menor densidade tecnológica.", "o centro de comunicação e coordenadora do cuidado, ordenando os fluxos na rede.", "um serviço voltado exclusivamente às condições agudas."], "correct": 3, "c": "As RAS são poliárquicas (não piramidais): a APS é o centro de comunicação, coordenadora do cuidado e ordenadora da rede. Menor densidade tecnológica não significa menor importância."}, {"tema": "SUS/PNAB", "q": "Segundo a PNAB (Portaria 2.436/2017), a composição mínima da equipe de Saúde da Família (eSF) inclui", "ops": ["médico, enfermeiro, técnico de enfermagem e agente de combate às endemias.", "médico, enfermeiro, farmacêutico e assistente social.", "médico, enfermeiro, cirurgião-dentista e auxiliar de saúde bucal.", "apenas médico, enfermeiro e agentes comunitários de saúde.", "médico, enfermeiro, auxiliar ou técnico de enfermagem e agentes comunitários de saúde."], "correct": 4, "c": "A eSF mínima: médico (pref. de família), enfermeiro, auxiliar/técnico de enfermagem e ACS. A saúde bucal (eSB) é acoplável, não obrigatória na composição mínima."}, {"tema": "SUS/eMulti", "q": "As Equipes Multiprofissionais na Atenção Primária (eMulti, Portaria 635/2023), que substituíram o NASF, atuam predominantemente por meio do", "ops": ["encaminhamento direto dos usuários à atenção especializada.", "atendimento como porta de entrada preferencial do sistema.", "gerenciamento administrativo das Unidades Básicas de Saúde.", "apoio matricial às equipes de Saúde da Família, com suporte técnico-pedagógico e assistencial.", "atendimento hospitalar de média e alta complexidade."], "correct": 3, "c": "A eMulti apoia (matricia) as eSF — não é porta de entrada nem substitui a equipe de referência; amplia a resolutividade. O farmacêutico integra esse cuidado multiprofissional."}, {"tema": "SUS/PNH", "q": "Na Política Nacional de Humanização (HumanizaSUS), o acolhimento é corretamente definido como", "ops": ["um setor físico de triagem que seleciona quem será atendido.", "um documento assinado pelo usuário ao entrar no serviço.", "uma postura de escuta qualificada e responsabilização, feita por qualquer profissional em qualquer momento.", "a classificação de risco realizada exclusivamente pelo enfermeiro.", "um dispositivo restrito às unidades de urgência e emergência."], "correct": 2, "c": "Acolhimento ≠ triagem: é postura/atitude de escuta e inclusão, não um lugar. A classificação de risco (ex.: Manchester) organiza o acesso por gravidade, e é distinta do acolhimento."}, {"tema": "SUS/PNVS", "q": "Segundo a Política Nacional de Vigilância em Saúde (Resolução CNS 588/2018), são componentes (vigilâncias) que a política articula", "ops": ["epidemiológica, sanitária, em saúde ambiental e do trabalhador.", "epidemiológica, sanitária, tecnológica e patrimonial.", "epidemiológica, hospitalar, laboratorial e farmacêutica.", "sanitária, ambiental, nutricional e escolar.", "sanitária, do trabalhador, laboratorial e financeira."], "correct": 0, "c": "As 4 vigilâncias: epidemiológica, sanitária, em saúde ambiental e do trabalhador. Ações laboratoriais e análise de situação de saúde são transversais a todas."}, {"tema": "SUS/Vigilância", "q": "Sobre a notificação compulsória, é correto afirmar que", "ops": ["é registrada no Sistema de Informações sobre Mortalidade (SIM).", "só deve ser feita após a confirmação laboratorial do caso.", "basta a suspeita da doença ou agravo para notificar, não sendo necessária a confirmação diagnóstica.", "é responsabilidade exclusiva do médico assistente.", "tem prazo único semanal para todos os agravos."], "correct": 2, "c": "Para agravos de notificação compulsória, a suspeita já obriga a notificar (SINAN); eventos graves têm prazo imediato (24h). SIM = óbitos; SINASC = nascidos vivos."}, {"tema": "SUS/EPS", "q": "A Educação Permanente em Saúde (EPS) diferencia-se da educação continuada porque a EPS", "ops": ["baseia-se em conteúdos pré-definidos transmitidos de forma descendente.", "ocorre fora do ambiente de trabalho, em cursos formais.", "restringe-se à capacitação de gestores.", "parte dos problemas do cotidiano do trabalho (ascendente), é coletiva e visa transformar as práticas.", "é pontual, centrada na atualização técnica individual."], "correct": 3, "c": "EPS = aprendizagem no/pelo trabalho, problematizadora, coletiva, ascendente, transformadora; inclui a continuada, mas a supera. Base: aprendizagem significativa/problematização (Paulo Freire)."}, {"tema": "SUS/Equidade", "q": "O uso do termo 'populações vulnerabilizadas' (em vez de 'vulneráveis') destaca que", "ops": ["a condição é permanente e não passível de intervenção.", "trata-se apenas de uma diferença estatística entre grupos.", "esses grupos são naturalmente mais frágeis e dependentes.", "as políticas de saúde não conseguem alcançá-los.", "a vulnerabilidade resulta de um processo social, e não de uma característica natural do grupo."], "correct": 4, "c": "'Vulnerabilizados' evidencia o processo social (racismo, pobreza, estigma) que produz maior exposição a riscos e menor acesso — combatendo iniquidades (diferenças injustas e evitáveis)."}, {"tema": "Segurança/PNSP", "q": "O Programa Nacional de Segurança do Paciente (Portaria 529/2013) define segurança do paciente como", "ops": ["a punição dos profissionais que cometem erros assistenciais.", "a garantia de ausência de eventos adversos nos serviços.", "a certificação de qualidade dos estabelecimentos de saúde.", "a eliminação completa de qualquer risco durante a assistência.", "a redução, a um mínimo aceitável, do risco de dano desnecessário associado ao cuidado de saúde."], "correct": 4, "c": "Segurança do paciente = reduzir a um mínimo aceitável o risco de dano desnecessário (risco zero não existe). A cultura é justa e não punitiva, focada no sistema."}, {"tema": "Segurança/Metas", "q": "Na identificação correta do paciente (1ª meta internacional de segurança), deve-se", "ops": ["utilizar o número do leito como identificador principal.", "usar pelo menos dois identificadores, como nome completo e data de nascimento.", "confiar apenas na confirmação verbal do acompanhante.", "identificar o paciente somente antes de procedimentos cirúrgicos.", "usar exclusivamente o número do prontuário."], "correct": 1, "c": "Usar ≥2 identificadores (nome completo + data de nascimento); nunca o número do leito/quarto. Vale para toda medicação, procedimento e coleta."}, {"tema": "Segurança/Erros", "q": "Na escrita segura da dose (protocolo de segurança na prescrição), é recomendado", "ops": ["usar zero à direita para reforçar a dose (1,0 mg).", "usar ponto como separador decimal em vez de vírgula.", "omitir o zero à esquerda em frações (,5 mg).", "abreviar 'unidades' como 'U'.", "sempre usar zero à esquerda (0,5 mg) e nunca zero à direita (evitar 1,0 mg)."], "correct": 4, "c": "Zero à esquerda sempre (0,5); nunca zero à direita (1,0 pode virar 10). Não usar ponto no lugar da vírgula; não abreviar 'unidades' (U pode virar zero). Preferir número inteiro (500 mg)."}, {"tema": "Segurança/MAV", "q": "São considerados medicamentos potencialmente perigosos (de alta vigilância), cujo erro tem alto risco de dano grave,", "ops": ["metformina, losartana, sinvastatina e hidroclorotiazida.", "paracetamol, dipirona, omeprazol e loratadina.", "insulina, anticoagulantes, opioides e eletrólitos concentrados (KCl).", "soro fisiológico, vitamina C, complexo B e antiácidos.", "amoxicilina, cefalexina, azitromicina e nistatina."], "correct": 2, "c": "MAV/MPP: insulina, anticoagulantes (heparina, varfarina), opioides, eletrólitos concentrados (KCl, NaCl hipertônico), quimioterápicos, bloqueadores neuromusculares. Exigem dupla checagem e restrição de acesso."}, {"tema": "NR32", "q": "Segundo a NR 32 (segurança e saúde no trabalho em serviços de saúde), é vedado", "ops": ["constituir comissão para prevenção de acidentes com perfurocortantes.", "oferecer imunização gratuita aos trabalhadores.", "reencapar agulhas ou proceder à sua retirada manual.", "manter lavatório exclusivo para higiene das mãos.", "fornecer EPI aos trabalhadores expostos."], "correct": 2, "c": "A NR 32 protege o TRABALHADOR: veda reencapar agulhas e o uso de adornos por quem tem contato com pacientes; a imunização é gratuita e é direito; luvas não substituem a lavagem das mãos."}, {"tema": "Bioética", "q": "No principialismo de Beauchamp & Childress, o dever de 'não causar dano' (primum non nocere) corresponde ao princípio da", "ops": ["autonomia.", "beneficência.", "justiça.", "não maleficência.", "integralidade."], "correct": 3, "c": "Não maleficência = não causar dano; beneficência = fazer o bem/agir no melhor interesse. São distintos. Autonomia = autodeterminação (base do TCLE); justiça = distribuição equitativa."}, {"tema": "Bioética/Fim de vida", "q": "A conduta de não prolongar artificialmente a vida nem antecipar a morte, permitindo que ela ocorra no tempo natural com cuidados paliativos, denomina-se", "ops": ["distanásia.", "mistanásia.", "suicídio assistido.", "eutanásia.", "ortotanásia."], "correct": 4, "c": "Ortotanásia (aceita, CFM 1.805/2006) = morte no tempo certo, sem obstinação. Eutanásia = antecipar ativamente a morte (vedada); distanásia = obstinação terapêutica; mistanásia = morte social evitável."}, {"tema": "Bioética/Pesquisa", "q": "No sistema brasileiro de ética em pesquisa, a análise ética local/institucional dos projetos é feita pelo", "ops": ["Conselho Nacional de Saúde (CNS), diretamente.", "Conselho Regional de Farmácia (CRF).", "Ministério Público, por meio de parecer prévio.", "Comitê de Ética em Pesquisa apenas em pesquisas com animais.", "Comitê de Ética em Pesquisa (CEP)."], "correct": 4, "c": "CEP = análise local/institucional; CONEP = instância nacional (ligada ao CNS). Submissão pela Plataforma Brasil. Res. CNS 466/2012 rege a pesquisa com seres humanos; Lei 14.874/2024 é o novo marco."}, {"tema": "Farmacoepidemiologia", "q": "Um estudo que parte do desfecho (doentes × não doentes) e investiga a exposição passada, calculando o Odds Ratio, é do tipo", "ops": ["ensaio clínico randomizado.", "ecológico.", "caso-controle.", "transversal.", "coorte."], "correct": 2, "c": "Caso-controle 'olha para trás' (parte da doença → OR); bom para doenças raras, sujeito a viés de memória. Coorte parte da exposição e segue no tempo (RR/incidência)."}, {"tema": "Farmacoepidemiologia", "q": "A Dose Diária Definida (DDD), da metodologia ATC/DDD da OMS, é corretamente descrita como", "ops": ["a dose de ataque de um fármaco de janela estreita.", "a dose máxima diária recomendada em bula.", "a quantidade de medicamento dispensada por receita.", "a dose diária realmente prescrita ao paciente (PDD).", "uma unidade técnica de medida de consumo, não a dose a ser prescrita ao paciente."], "correct": 4, "c": "A DDD é unidade de medida (dose média de manutenção na indicação principal em adultos), usada para comparar consumo (DDD/1000 hab/dia ambulatorial; DDD/100 leitos-dia hospitalar). Difere da PDD."}, {"tema": "Interações/CYP450", "q": "Uma mulher em uso de contraceptivo oral inicia rifampicina para tuberculose. O risco farmacológico esperado é", "ops": ["síndrome serotoninérgica, por efeito aditivo.", "toxicidade estrogênica, por acúmulo do contraceptivo.", "falha contraceptiva, por indução do CYP3A4 e aumento do metabolismo do contraceptivo.", "ausência de interação clinicamente relevante.", "trombose, por inibição enzimática."], "correct": 2, "c": "A rifampicina é indutor enzimático potente (CYP3A4): acelera o metabolismo do contraceptivo, reduz o nível e causa falha contraceptiva. Indução tem início lento (1–2 semanas)."}, {"tema": "Interações/CYP450", "q": "Paciente em uso de sinvastatina inicia claritromicina e evolui com mialgia intensa e elevação de CPK. O mecanismo é", "ops": ["antagonismo farmacodinâmico no receptor.", "indução do CYP3A4, reduzindo a estatina.", "deslocamento da estatina da ligação proteica.", "inibição do CYP3A4 pela claritromicina, com acúmulo da estatina e risco de rabdomiólise.", "quelação da estatina no trato gastrointestinal."], "correct": 3, "c": "Macrolídeos (claritro/eritro) inibem o CYP3A4; a azitromicina não. O acúmulo de sinvastatina/atorvastatina eleva o risco de miopatia/rabdomiólise. Suspender a estatina durante o antibiótico."}, {"tema": "Interações/Pró-fármaco", "q": "Paciente coronariopata em uso de clopidogrel passa a usar omeprazol. A preocupação é", "ops": ["redução do efeito antiagregante, pois o omeprazol inibe o CYP2C19 e a ativação do clopidogrel.", "aumento do efeito antiagregante, com risco de sangramento.", "rabdomiólise por interação muscular.", "efeito dissulfiram com o álcool.", "hipercalemia por retenção renal."], "correct": 0, "c": "O clopidogrel é pró-fármaco ativado pelo CYP2C19; o omeprazol inibe essa via → menos fármaco ativo → perda de efeito (lógica invertida dos pró-fármacos). Preferir pantoprazol."}, {"tema": "Interações/Alimento", "q": "O efeito do suco de toranja (grapefruit) sobre a sinvastatina decorre de", "ops": ["inibição do CYP3A4 da parede intestinal, aumentando a biodisponibilidade da estatina.", "indução enzimática que reduz a estatina.", "quelação que impede a absorção da estatina.", "aumento da excreção renal da estatina.", "antagonismo do receptor da estatina."], "correct": 0, "c": "A toranja inibe o CYP3A4 intestinal (efeito dura até ~72 h), elevando estatinas, anlodipino e ciclosporina, com risco de miopatia. Erva-de-são-joão, ao contrário, é indutor."}, {"tema": "Interações/Excreção", "q": "Paciente em uso de lítio inicia ibuprofeno e evolui com tremor e confusão. A causa é", "ops": ["quelação do lítio no intestino.", "redução da excreção renal do lítio pelo AINE, elevando o nível sérico e causando intoxicação.", "indução do metabolismo hepático do lítio.", "efeito antagonista no receptor do lítio.", "deslocamento do lítio da ligação proteica."], "correct": 1, "c": "AINEs, tiazídicos e IECA/BRA reduzem a depuração renal do lítio → intoxicação (janela 0,6–1,2 mEq/L). O lítio é hidrossolúvel e eliminado por via renal."}, {"tema": "Interações/Farmacodinâmica", "q": "A associação de nitrato com sildenafila é contraindicada porque", "ops": ["reduz o efeito do nitrato por indução enzimática.", "gera arritmia por prolongamento do intervalo QT.", "quela o nitrato, impedindo sua absorção.", "causa crise hipertensiva por vasoconstrição.", "provoca vasodilatação aditiva com risco de hipotensão grave."], "correct": 4, "c": "Nitrato + inibidor de PDE5 (sildenafila/tadalafila) → vasodilatação somada (via NO/GMPc) e hipotensão grave. Interação farmacodinâmica; combinação contraindicada."}, {"tema": "Interações/Álcool", "q": "O 'efeito dissulfiram' (rubor, náusea, taquicardia ao ingerir álcool) é classicamente associado ao uso de", "ops": ["azitromicina.", "amoxicilina.", "paracetamol.", "omeprazol.", "metronidazol."], "correct": 4, "c": "O metronidazol (e o tinidazol, algumas cefalosporinas) inibe a aldeído-desidrogenase → acúmulo de acetaldeído com o álcool. Orientar abstinência durante e até ~72 h após."}, {"tema": "Interações/P-gp", "q": "O aumento do nível sérico da digoxina quando associada à amiodarona ou ao verapamil ocorre por", "ops": ["redução da ligação a receptores cardíacos.", "deslocamento da ligação à albumina.", "indução do CYP3A4.", "aumento da absorção intestinal por quelação.", "inibição da glicoproteína-P (P-gp), reduzindo o efluxo da digoxina."], "correct": 4, "c": "A digoxina é substrato-modelo da P-gp; inibidores (amiodarona, verapamil, claritromicina, quinidina) elevam seu nível → intoxicação digitálica. Reduzir a dose e monitorar."}, {"tema": "Interações/Clássicas", "q": "A combinação de varfarina com sulfametoxazol-trimetoprima tende a", "ops": ["não ter relevância clínica.", "causar rabdomiólise.", "aumentar o INR e o risco de sangramento, por inibição do CYP2C9.", "reduzir o INR por indução enzimática.", "provocar hipercalemia isolada."], "correct": 2, "c": "Sulfa, metronidazol, fluconazol e amiodarona inibem o CYP2C9 (que metaboliza a S-varfarina) → ↑ INR/sangramento. Monitorar INR e considerar antibiótico alternativo."}, {"tema": "Interações/Tipos", "q": "Quando dois medicamentos injetáveis são misturados na mesma seringa e formam precipitado antes da infusão, trata-se de interação", "ops": ["de excreção renal.", "farmacocinética, na fase de distribuição.", "farmacodinâmica, no receptor.", "farmacêutica (incompatibilidade físico-química), que ocorre fora do organismo.", "farmacocinética, na fase de metabolismo."], "correct": 3, "c": "Incompatibilidade farmacêutica ocorre in vitro (seringa/equipo/soro) — não é interação PK nem PD. Não misturar e lavar o acesso entre fármacos."}, {"tema": "Monitorização/Coleta", "q": "Como regra geral na monitorização terapêutica de medicamentos, a amostra de sangue para dosar o nível de manutenção deve ser colhida", "ops": ["somente após a primeira dose do fármaco.", "no pico, logo após a administração.", "no vale (imediatamente antes da próxima dose) e após o estado de equilíbrio.", "em qualquer momento, independentemente da dose.", "sempre 2 horas após a dose."], "correct": 2, "c": "Regra geral: colher no vale (menor concentração), após 4–5 meias-vidas (steady state). Aminoglicosídeos são exceção (pico + vale). Digoxina: ≥6–8 h pós-dose; lítio: 12 h."}, {"tema": "Monitorização/Digoxina", "q": "Um idoso em uso de digoxina e furosemida apresenta náusea, visão amarelada (xantopsia) e arritmia, com digoxina de 1,8 ng/mL. O provável fator precipitante é", "ops": ["indução do metabolismo da digoxina.", "aumento da excreção renal da digoxina.", "hipercalemia pela furosemida.", "alcalose por retenção de bicarbonato.", "hipocalemia induzida pela furosemida, que potencializa a toxicidade digitálica."], "correct": 4, "c": "A hipocalemia (furosemida espolia K⁺) potencializa a toxicidade da digoxina, mesmo com nível 'na faixa'. Corrigir K⁺/Mg²⁺, suspender a digoxina; casos graves → Fab antidigoxina."}, {"tema": "Monitorização/Fenitoína", "q": "Paciente com fenitoína total 'normal' (12 µg/mL) mas albumina de 2,0 g/dL apresenta nistagmo e ataxia. A explicação é", "ops": ["o nível total não sofre influência da albumina.", "a hipoalbuminemia eleva a fração livre (ativa), tornando o nível efetivamente tóxico.", "houve erro laboratorial sem repercussão clínica.", "a fenitoína está subterapêutica, exigindo aumento de dose.", "há indução do metabolismo pela própria fenitoína."], "correct": 1, "c": "A fenitoína é muito ligada à albumina; na hipoalbuminemia/IRC a fração livre sobe mesmo com nível total normal. Corrigir pela albumina ou medir fenitoína livre; cinética não linear."}, {"tema": "Monitorização/Vancomicina", "q": "Sobre a monitorização da vancomicina, a tendência atual das diretrizes é guiar a dose por", "ops": ["resposta clínica isolada, sem dosagem sérica.", "dosagem única após a primeira dose.", "alvo de exposição AUC/CIM (400–600), com coleta no estado de equilíbrio.", "medida do vale acima de 30 µg/mL.", "nível de pico 30 minutos após a infusão."], "correct": 2, "c": "Vancomicina é AUC-dependente; diretriz atual: alvo AUC/CIM 400–600 (antes usava-se vale 15–20 µg/mL). Vale alto = risco de nefrotoxicidade, não de eficácia."}, {"tema": "Monitorização/Efeito", "q": "Apesar de terem índice terapêutico estreito, a varfarina e a heparina não fracionada são monitoradas por", "ops": ["contagem de plaquetas apenas.", "efeito (INR e TTPa, respectivamente), e não por concentração plasmática.", "concentração sérica do fármaco.", "dosagem de metabólitos na urina.", "nível de pico e vale."], "correct": 1, "c": "Varfarina é monitorada pelo INR (alvo 2–3); heparina não fracionada pelo TTPa (1,5–2,5× controle). São de IT estreito, mas guiadas por efeito, não por nível sérico."}, {"tema": "RAM/Classificação", "q": "Osteoporose por corticoide e nefropatia por uso crônico de analgésicos são exemplos de reação adversa a medicamento do tipo", "ops": ["B (bizarra, imunológica).", "E (retirada).", "C (crônica, relacionada à dose cumulativa e ao tempo de uso).", "D (tardia).", "A (aumentada, dose-dependente aguda)."], "correct": 2, "c": "RAM tipo C (crônicas) relacionam-se ao uso prolongado/dose cumulativa. Tipo A = exagero do efeito (dose-dependente); B = idiossincrásica/imune; D = tardia (teratogênese); E = retirada/rebote."}, {"tema": "RAM/Tipo A×B", "q": "A conduta típica diante de uma RAM do tipo A (aumentada) é", "ops": ["trocar por outro fármaco da mesma classe sem ajuste.", "administrar corticoide e anti-histamínico.", "reduzir a dose do medicamento.", "suspender definitivamente e contraindicar o fármaco.", "manter a dose e apenas observar."], "correct": 2, "c": "RAM tipo A é previsível e dose-dependente (exagero do efeito farmacológico) → conduta: reduzir a dose. RAM tipo B (imprevisível/imune, ex.: anafilaxia) → suspender."}, {"tema": "Farmacovigilância/Notificação", "q": "No Brasil, a suspeita de reação adversa a um medicamento deve ser notificada no", "ops": ["SIM, sistema de mortalidade.", "e-SUS AB, da Atenção Básica.", "SINAN, sistema de agravos de notificação.", "VigiMed (sistema da ANVISA para eventos adversos de medicamentos e vacinas).", "NOTIVISA, destinado a queixas técnicas de qualidade."], "correct": 3, "c": "Eventos adversos de medicamentos/vacinas → VigiMed; queixas técnicas (desvio de qualidade) → Notivisa. Basta a suspeita para notificar (não é preciso confirmar o nexo)."}, {"tema": "Farmacovigilância/Método", "q": "O método principal da farmacovigilância pós-comercialização, amplo e barato, porém sujeito a subnotificação e sem cálculo de incidência, é", "ops": ["a monitorização intensiva em hospital-sentinela.", "a notificação espontânea (vigilância passiva).", "o estudo caso-controle pareado.", "o ensaio clínico randomizado de fase III.", "a coorte prospectiva com denominador definido."], "correct": 1, "c": "A notificação espontânea gera sinais/hipóteses (barata, ampla), mas subnotifica e não fornece denominador/incidência. Estudos analíticos (coorte/caso-controle) quantificam o risco."}, {"tema": "Seguimento/Cardiologia", "q": "Paciente hipertenso em uso de enalapril desenvolve tosse seca persistente sem outra causa. A conduta mais adequada é", "ops": ["suspender qualquer anti-hipertensivo.", "associar um antitussígeno e manter o enalapril.", "trocar por outro IECA, como o captopril.", "substituir o IECA por um BRA (bloqueador do receptor de angiotensina), que não causa tosse.", "reduzir a dose e associar um diurético de alça."], "correct": 3, "c": "A tosse seca é RAM clássica dos IECA (acúmulo de bradicinina). Substituir por BRA (–sartana) controla a PA sem tosse. Manter vigilância de potássio e função renal."}, {"tema": "Seguimento/IC", "q": "São as quatro classes que reduzem mortalidade na insuficiência cardíaca com fração de ejeção reduzida (os '4 pilares')", "ops": ["diurético de alça, digoxina, nitrato e AINE.", "IECA/BRA ou INRA, betabloqueador, antagonista mineralocorticoide e iSGLT2.", "IECA, diurético tiazídico, digoxina e ivabradina.", "betabloqueador, amiodarona, varfarina e furosemida.", "bloqueador de canal de cálcio, estatina, AAS e omeprazol."], "correct": 1, "c": "Os 4 pilares da ICFER: IECA/BRA ou sacubitril-valsartana (INRA) + betabloqueador + espironolactona + iSGLT2. Diuréticos de alça aliviam congestão, mas não mudam mortalidade; AINEs pioram a IC."}, {"tema": "Seguimento/Idoso", "q": "No idoso, a alteração farmacocinética mais relevante para o ajuste de doses é a", "ops": ["redução da excreção renal (queda da filtração glomerular).", "elevação da albumina sérica.", "aumento da água corporal total.", "elevação da massa muscular, que aumenta a creatinina.", "redução da absorção intestinal, que compromete a extensão da absorção."], "correct": 0, "c": "A ↓ excreção renal prolonga a meia-vida de fármacos renais (digoxina, lítio, aminoglicosídeos). A creatinina 'normal' pode mascarar a queda renal (menor massa muscular) — estimar a depuração."}, {"tema": "Seguimento/Idoso", "q": "A situação em que uma reação adversa a um medicamento é interpretada como nova doença e tratada com outro medicamento, gerando nova RAM, denomina-se", "ops": ["cascata iatrogênica (prescrição em cascata).", "polifarmácia apropriada.", "desprescrição.", "adesão terapêutica.", "conciliação medicamentosa."], "correct": 0, "c": "Cascata iatrogênica: ex.: BCC → edema → diurético; metoclopramida → parkinsonismo → antiparkinsoniano. Antes de adicionar fármaco para sintoma novo, questionar se não é efeito de outro em uso."}, {"tema": "Seguimento/Idoso", "q": "A ferramenta que sinaliza medicamentos indicados que foram OMITIDOS e deveriam ser iniciados no idoso (subtratamento) é o critério", "ops": ["START.", "STOPP.", "Beers.", "Morisky-Green.", "Naranjo."], "correct": 0, "c": "START (Screening Tool to Alert to Right Treatment) aponta omissões (ex.: não anticoagular na FA). STOPP aponta o que suspender; Beers lista medicamentos potencialmente inapropriados a evitar."}, {"tema": "Seguimento/Pediatria", "q": "A prescrição de tetraciclina para uma criança de 3 anos é inadequada porque", "ops": ["desencadeia a síndrome de Reye em viroses.", "provoca a síndrome do bebê cinzento no neonato.", "provoca kernicterus por deslocar a bilirrubina.", "causa depressão respiratória por metabolização ultrarrápida.", "causa manchas e hipoplasia do esmalte dentário em menores de 8 anos."], "correct": 4, "c": "Tetraciclinas são evitadas em <8 anos (dentes/ossos). Bebê cinzento = cloranfenicol no neonato; Reye = AAS em viroses; depressão respiratória = codeína <12 anos; kernicterus = sulfas/ceftriaxona no neonato."}, {"tema": "Seguimento/Pediatria", "q": "No neonato, a coadministração de ceftriaxona com soluções contendo cálcio por via endovenosa é contraindicada porque", "ops": ["induz o metabolismo hepático da ceftriaxona.", "pode precipitar (sais de ceftriaxona-cálcio), com risco de embolia.", "reduz a absorção oral do antibiótico.", "causa efeito dissulfiram.", "provoca a síndrome do homem vermelho."], "correct": 1, "c": "Ceftriaxona + cálcio EV em neonatos → precipitação (risco de embolia); além disso a ceftriaxona desloca a bilirrubina (risco de kernicterus). Evitar a associação nessa faixa."}, {"tema": "Processo de cuidado", "q": "Na terminologia do cuidado farmacêutico, o PRM (Problema Relacionado a Medicamento) e o RNM (Resultado Negativo associado à Medicação) diferenciam-se porque", "ops": ["o PRM é o resultado clínico e o RNM é a causa.", "ambos designam o mesmo evento.", "o RNM é sempre uma reação alérgica.", "o PRM só existe no ambiente hospitalar e o RNM no ambulatório.", "o PRM é a causa (circunstância do processo de uso) e o RNM é o resultado clínico negativo."], "correct": 4, "c": "PRM = causa (dose inadequada, interação, não adesão); RNM = consequência clínica (necessidade, efetividade, segurança). Ex.: a não adesão (PRM) gera inefetividade (RNM)."}, {"tema": "Processo de cuidado/SOAP", "q": "No registro SOAP, o dado 'PA 165/100 mmHg' e o relato 'paciente refere tontura' classificam-se, respectivamente, como", "ops": ["Plano (P) e Subjetivo (S).", "Avaliação (A) e Plano (P).", "Objetivo (O) e Subjetivo (S).", "Objetivo (O) e Avaliação (A).", "Subjetivo (S) e Objetivo (O)."], "correct": 2, "c": "S = relatado pelo paciente (subjetivo); O = mensurável/exames (objetivo). 'PA 165/100' é O; 'refere tontura' é S. A = análise/PRM-RNM; P = plano/condutas."}, {"tema": "Adesão", "q": "Um paciente hipertenso interrompe a medicação porque 'se sente bem e não sente nada'. Essa não adesão é classificada como", "ops": ["intencional, relacionada à crença e ao caráter assintomático da doença.", "não intencional, por esquecimento.", "primária, por não retirar o medicamento.", "farmacêutica, por incompatibilidade.", "involuntária, por dificuldade visual."], "correct": 0, "c": "'Parei porque me sinto bem/tenho medo' = não adesão intencional (crença). Esquecimento = não intencional. HAS assintomática favorece a não adesão. Conduta: educar e negociar (concordância)."}, {"tema": "Adesão", "q": "Entre as estratégias para melhorar a adesão ao tratamento, a de maior eficácia comprovada é", "ops": ["aumentar o número de tomadas diárias para reforçar.", "trocar por fitoterápicos e homeopáticos.", "prescrever a forma injetável de rotina.", "simplificar o regime (menos doses/dia, associações em dose fixa).", "prescrever medicamentos mais caros e modernos."], "correct": 3, "c": "Simplificar o regime (1×/dia, dose fixa combinada) é das estratégias mais eficazes. Combinar tipo de não adesão com a estratégia (esquecimento → lembrete/simplificação; crença → educação)."}, {"tema": "CFF 585/586", "q": "Segundo a Resolução CFF nº 586/2013, o farmacêutico pode prescrever de forma autônoma", "ops": ["medicamentos isentos de prescrição (MIPs), plantas medicinais e preparações magistrais isentas de prescrição.", "antimicrobianos sistêmicos por conta própria.", "substâncias da Portaria 344/98 das listas A e B.", "medicamentos sob prescrição médica sem protocolo.", "qualquer medicamento tarjado, desde que documente o ato."], "correct": 0, "c": "Art. 5º: prescrição autônoma limita-se a MIPs, plantas medicinais/drogas vegetais e magistrais isentos. Tarjados (Art. 6º) exigem diagnóstico prévio + protocolo/acordo + título de especialista."}, {"tema": "CFF 585/586", "q": "A diferença entre as Resoluções CFF 585 e 586/2013 é que", "ops": ["a 586 revogou integralmente a 585.", "a 585 regulamenta as atribuições clínicas do farmacêutico e a 586 regula a prescrição farmacêutica.", "ambas tratam exclusivamente da dispensação.", "a 585 é da ANVISA e a 586 do Ministério da Saúde.", "a 585 trata da prescrição e a 586 das atribuições."], "correct": 1, "c": "585 = 'guarda-chuva' das atribuições clínicas; 586 = detalha uma delas (a prescrição). Mesma data (29/08/2013). A aplicabilidade da 586 é judicialmente disputada."}, {"tema": "Antimicrobianos/Mecanismo", "q": "O mecanismo de ação da vancomicina, usada contra MRSA, é", "ops": ["inibição da DNA-girase.", "inibição da subunidade ribossomal 30S.", "desorganização da membrana de forma cálcio-dependente.", "ligação ao terminal D-Ala-D-Ala do precursor da parede, bloqueando a polimerização do peptidoglicano.", "inibição da transpeptidase por ligação às PBP, como os β-lactâmicos."], "correct": 3, "c": "A vancomicina (glicopeptídeo) liga-se ao D-Ala-D-Ala, bloqueando a parede — só age em Gram+. A resistência (VRE) troca o alvo para D-Ala-D-Lac. Ligação às PBP = β-lactâmicos; 30S = aminoglicosídeos."}, {"tema": "Antimicrobianos/PK-PD", "q": "Os β-lactâmicos (penicilinas, cefalosporinas, carbapenêmicos) têm eficácia otimizada por serem", "ops": ["AUC-dependentes, com alvo AUC/CIM ≥ 400.", "independentes da farmacocinética.", "tempo-dependentes (T > CIM), beneficiando-se de infusão estendida/contínua.", "dependentes exclusivamente do efeito pós-antibiótico.", "concentração-dependentes, exigindo dose única diária alta."], "correct": 2, "c": "β-lactâmico = tempo (T>CIM) → infusão estendida. Aminoglicosídeo/quinolona = concentração (pico alto, dose única diária). Vancomicina = AUC."}, {"tema": "Antimicrobianos/Espectro", "q": "Assinale o antimicrobiano que NÃO possui cobertura contra MRSA:", "ops": ["ceftarolina.", "daptomicina.", "vancomicina.", "linezolida.", "ceftriaxona."], "correct": 4, "c": "Cefalosporinas clássicas (ceftriaxona, 3ª geração) não cobrem MRSA; a exceção é a ceftarolina (5ª geração). Vancomicina, linezolida e daptomicina são opções para Gram+ resistentes."}, {"tema": "Antimicrobianos/Aplicação", "q": "Apesar de ativa contra MRSA, a daptomicina não deve ser usada em pneumonia porque", "ops": ["é inativada pelo surfactante pulmonar.", "não tem ação contra Gram-positivos.", "não atinge concentração sérica adequada.", "é antagonizada pelo oxigênio alveolar.", "provoca pneumonite química."], "correct": 0, "c": "A daptomicina é inativada pelo surfactante, perdendo eficácia no pulmão — reservada a bacteremia/endocardite e pele/partes moles. Monitorar CPK (miopatia)."}, {"tema": "Antimicrobianos/Aminoglicosídeos", "q": "Sobre os aminoglicosídeos (gentamicina, amicacina), é correto afirmar que são", "ops": ["isentos de sinergia com β-lactâmicos.", "bacteriostáticos de amplo espectro, incluindo anaeróbios.", "ativos contra anaeróbios estritos.", "bactericidas concentração-dependentes, com risco de nefro e ototoxicidade, atuando na 30S.", "atuantes na subunidade ribossomal 50S."], "correct": 3, "c": "Aminoglicosídeos: 30S, bactericidas concentração-dependentes, nefro/ototóxicos, inativos em anaeróbios (captação O₂-dependente); fazem sinergia com β-lactâmicos (endocardite enterocócica)."}, {"tema": "Antimicrobianos/Reações", "q": "A síndrome do 'homem vermelho' (rubor e prurido em face/tronco) durante a infusão de vancomicina", "ops": ["é uma reação alérgica IgE-mediada que contraindica o fármaco.", "decorre da infusão rápida (liberação de histamina) e não é alergia; corrige-se reduzindo a velocidade.", "indica falência terapêutica e exige troca imediata.", "resulta de contaminação bacteriana da solução.", "é sinal de nefrotoxicidade estabelecida."], "correct": 1, "c": "A 'red man syndrome' é reação à infusão rápida (histamina), NÃO alergia. Conduta: diminuir a velocidade de infusão; não é necessário suspender definitivamente."}, {"tema": "Antimicrobianos/Descalonamento", "q": "No gerenciamento de antimicrobianos (stewardship), 'descalonar' significa", "ops": ["aumentar a dose para acelerar a resposta.", "trocar para um antibiótico de espectro mais amplo.", "estreitar o espectro para o menor eficaz, guiado pela cultura e antibiograma.", "suspender o antibiótico assim que houver melhora clínica.", "associar dois antibióticos de mesmo espectro."], "correct": 2, "c": "Descalonamento = estreitar o espectro guiado pela cultura, mantendo a eficácia — não é suspender. É a intervenção de stewardship mais cobrada, junto do switch IV→VO."}, {"tema": "Antimicrobianos/Profilaxia", "q": "Na profilaxia antibiótica cirúrgica, o antibiótico deve ser administrado, em geral, dentro de", "ops": ["24 horas antes da cirurgia.", "48 horas antes, por via oral.", "no momento da alta, para prevenir infecção tardia.", "apenas após o término do procedimento.", "60 minutos antes da incisão (até 120 minutos para vancomicina e fluoroquinolonas)."], "correct": 4, "c": "Profilaxia: 60 min antes da incisão (120 para vanco/quinolona, infusão lenta); em geral dose única; não prolongar > 24 h (prolongar não reduz ISC e aumenta resistência)."}, {"tema": "Resistência/ESBL", "q": "Uma urocultura mostra E. coli produtora de ESBL, resistente à ceftriaxona. A melhor opção terapêutica para infecção grave é", "ops": ["um carbapenêmico (ex.: meropenem).", "azitromicina.", "amoxicilina-clavulanato oral.", "vancomicina.", "ceftriaxona em dose dobrada."], "correct": 0, "c": "ESBL hidrolisa cefalosporinas de 3ª/4ª geração → tratar com carbapenêmico (meropenem; ertapenem se sem Pseudomonas). Não hidrolisa carbapenêmicos (diferença do KPC)."}, {"tema": "Resistência/KPC", "q": "A Klebsiella pneumoniae produtora de carbapenemase (KPC) resiste a", "ops": ["apenas às penicilinas, sendo sensível às cefalosporinas.", "exclusivamente à vancomicina.", "apenas às fluoroquinolonas.", "somente aos aminoglicosídeos.", "carbapenêmicos, exigindo opções como polimixina B/colistina ou ceftazidima-avibactam."], "correct": 4, "c": "KPC hidrolisa carbapenêmicos (e cefalosporinas, penicilinas, aztreonam). Opções: polimixina B/colistina, ceftazidima-avibactam, combinações. ESBL → carbapenêmico; KPC → polimixina/ceftaz-avibactam."}, {"tema": "Resistência/MRSA", "q": "O fenótipo MRSA (resistência à oxacilina) é mediado principalmente por", "ops": ["bomba de efluxo.", "alteração da proteína ligadora de penicilina (PBP2a, gene mecA).", "produção de carbapenemase.", "produção de penicilinase.", "perda de porinas."], "correct": 1, "c": "O MRSA expressa a PBP2a (gene mecA), de baixa afinidade pelos β-lactâmicos — resistente a quase todos, exceto a ceftarolina. A penicilinase explica a resistência à penicilina G, não o fenótipo MRSA."}, {"tema": "Infecção hospitalar/Precauções", "q": "Um paciente com suspeita de tuberculose pulmonar bacilífera exige precaução para", "ops": ["contato: luvas e avental, com quarto privativo.", "aerossóis: quarto com pressão negativa e máscara N95/PFF2.", "padrão apenas, sem barreiras adicionais.", "gotículas: máscara cirúrgica e distância de 1 metro.", "aerossóis, dispensando quarto especial."], "correct": 1, "c": "TB, sarampo e varicela = aerossóis (N95 + pressão negativa). Gotículas (influenza, meningococo) = máscara cirúrgica. Contato (MRSA, VRE, C. difficile) = luvas + avental."}, {"tema": "Infecção hospitalar/C. difficile", "q": "Diante de diarreia por Clostridioides difficile, a higiene das mãos deve ser feita com", "ops": ["solução de clorexidina degermante somente.", "nenhuma medida específica além da precaução padrão.", "água apenas, sem sabão.", "água e sabão, pois o álcool gel não elimina os esporos.", "apenas álcool gel a 70%, que é suficiente."], "correct": 3, "c": "C. difficile: precaução de contato + higiene das mãos com ÁGUA E SABÃO (o álcool não mata esporos). Tratamento: vancomicina VO ou fidaxomicina; suspender o antibiótico desencadeante."}, {"tema": "Infecção hospitalar/Bundle", "q": "No bundle de prevenção da pneumonia associada à ventilação (PAV), uma medida-chave é", "ops": ["manter a cabeceira elevada a 30–45°.", "manter o paciente em decúbito horizontal (0°).", "administrar antibiótico profilático contínuo.", "trocar o circuito do ventilador a cada 6 horas.", "manter sedação profunda contínua sem despertar diário."], "correct": 0, "c": "Bundle da PAV: cabeceira 30–45°, higiene oral com clorexidina, despertar diário + teste de extubação, profilaxia de TEV e úlcera de estresse, aspiração subglótica. Retirar o dispositivo o quanto antes."}, {"tema": "Infecção hospitalar/Terapia sequencial", "q": "A troca da via intravenosa para a oral (terapia sequencial/switch IV→VO) é apropriada quando o paciente está", "ops": ["ainda febril e instável, para agilizar a alta.", "em ventilação mecânica com sedação profunda.", "em uso de fármaco sem absorção oral.", "no primeiro dia de antibioticoterapia.", "estável, afebril, tolerando a via oral e com fármaco de boa biodisponibilidade."], "correct": 4, "c": "Switch IV→VO: paciente estável, afebril, aceitando VO, com fármaco de boa biodisponibilidade (fluoroquinolonas, linezolida, metronidazol, SMX-TMP). Reduz flebite, custo e internação."}, {"tema": "Oncologia/Antídoto", "q": "Na cistite hemorrágica induzida por ciclofosfamida/ifosfamida (acroleína), a prevenção é feita com", "ops": ["naloxona.", "alopurinol.", "dexrazoxano.", "ácido folínico (leucovorin).", "MESNA e hidratação vigorosa."], "correct": 4, "c": "A acroleína (metabólito) causa cistite hemorrágica; a MESNA a neutraliza no trato urinário. Leucovorin = resgate do metotrexato; dexrazoxano = cardioproteção das antraciclinas."}, {"tema": "Oncologia/MTX", "q": "No protocolo com metotrexato em altas doses, o agente usado como 'resgate' para limitar a toxicidade nas células normais é", "ops": ["o dexrazoxano.", "a rasburicase.", "a MESNA.", "o ácido folínico (leucovorin / folinato de cálcio).", "a vitamina K."], "correct": 3, "c": "O ácido folínico repõe folato reduzido nas células normais, limitando a toxicidade do MTX (mucosite, mielossupressão) sem anular o efeito antitumoral. Exige hidratação e alcalinização urinária."}, {"tema": "Oncologia/Cardiotoxicidade", "q": "A toxicidade cumulativa dose-limitante das antraciclinas (ex.: doxorrubicina) é a", "ops": ["cistite hemorrágica.", "neuropatia periférica.", "nefrotoxicidade.", "cardiotoxicidade (cardiomiopatia/insuficiência cardíaca).", "toxicidade pulmonar (fibrose)."], "correct": 3, "c": "Antraciclinas → cardiotoxicidade cumulativa (monitorar FEVE; dexrazoxano protege). Bleomicina → pulmão; cisplatina → nefro/oto; vincristina → neuropatia."}, {"tema": "Oncologia/Erro-sentinela", "q": "A vincristina deve ser administrada exclusivamente por via", "ops": ["subcutânea, para reduzir a dor.", "intramuscular, para absorção lenta.", "intratecal, para atingir o sistema nervoso central.", "oral, por boa biodisponibilidade.", "endovenosa, sendo a via intratecal fatal (neurotoxicidade ascendente)."], "correct": 4, "c": "Vincristina por via intratecal é FATAL (neurotoxicidade ascendente) — erro-sentinela. A via correta é EV. Deve ser rotulada e segregada para evitar a troca de via."}, {"tema": "Oncologia/Manipulação", "q": "A manipulação de antineoplásicos injetáveis deve ser realizada em", "ops": ["fluxo laminar horizontal, para proteger o produto.", "sala sem controle de pressão, com luvas simples.", "capela de exaustão química comum.", "cabine de segurança biológica (fluxo laminar vertical, classe II), sob responsabilidade do farmacêutico.", "bancada aberta com uso de máscara cirúrgica."], "correct": 3, "c": "Antineoplásicos (medicamentos perigosos) exigem cabine de segurança biológica classe II (fluxo vertical), sala com pressão negativa e farmacêutico responsável (RDC 220/2004 + NR 32)."}, {"tema": "Nutrição/Via", "q": "Quando o trato gastrointestinal está funcionante, a via de terapia nutricional preferencial é a", "ops": ["sempre a oral exclusiva, mesmo sem ingestão adequada.", "indiferente, escolhendo-se pela conveniência.", "enteral, por ser mais fisiológica, preservar o trofismo intestinal e ter menor risco de infecção.", "parenteral central, por permitir maior aporte calórico.", "parenteral periférica, por ser mais segura."], "correct": 2, "c": "'Se o intestino funciona, use-o': a nutrição enteral é preferível à parenteral — mais fisiológica, mantém o trofismo, menos infecção e menor custo. A parenteral é para quem não pode usar o TGI."}, {"tema": "Nutrição/Realimentação", "q": "Ao realimentar um paciente gravemente desnutrido, a alteração laboratorial que marca a síndrome de realimentação é a", "ops": ["hipercalcemia.", "hiperfosfatemia com hipercalemia.", "hipofosfatemia (com hipocalemia e hipomagnesemia).", "hiperglicemia sem distúrbio eletrolítico.", "hipernatremia isolada."], "correct": 2, "c": "Na realimentação, a insulina (resposta à glicose) empurra fosfato, K⁺ e Mg²⁺ para dentro das células → hipofosfatemia grave + hipoK/hipoMg e deficiência de tiamina. Iniciar devagar e repor eletrólitos/tiamina."}, {"tema": "Nutrição/NP", "q": "Na nutrição parenteral, a incompatibilidade físico-química clássica que pode precipitar na bolsa é a de", "ops": ["glicose e aminoácidos.", "lipídios e água.", "sódio e potássio.", "vitaminas e oligoelementos.", "cálcio e fosfato."], "correct": 4, "c": "A precipitação cálcio-fosfato pode causar embolia; o farmacêutico controla concentrações, ordem de adição e estabilidade. Não se adicionam medicamentos à bolsa sem compatibilidade comprovada."}, {"tema": "Gestão/Curvas", "q": "Nas curvas de gestão de estoque, a curva ABC classifica os itens por", "ops": ["valor financeiro (consumo × preço), pelo princípio de Pareto.", "criticidade clínica (impacto da falta).", "popularidade/giro (frequência de saída).", "prazo de validade dos produtos.", "volume físico ocupado no estoque."], "correct": 0, "c": "ABC = valor financeiro (classe A: poucos itens, muito valor → controle rigoroso). XYZ = criticidade (Z = vital). Um item pode ser C (barato) e Z (vital), como o soro fisiológico — daí combinar as curvas."}, {"tema": "Gestão/FEFO", "q": "Na dispensação hospitalar, a regra de saída dos medicamentos prioriza", "ops": ["o de menor volume de estoque.", "o de entrada mais antiga (FIFO), independentemente da validade.", "o de maior valor unitário primeiro.", "o de validade mais próxima (FEFO — primeiro que vence, primeiro que sai).", "a escolha do profissional que dispensa."], "correct": 3, "c": "FEFO (first expire, first out): prioriza a validade, pois um lote que entrou depois pode vencer antes. Evita perdas por vencimento."}, {"tema": "Gestão/Ponto de pedido", "q": "Com consumo médio de 100 unidades/mês, prazo de reposição de 1 mês e estoque de segurança de 50, o ponto de pedido é", "ops": ["50 unidades.", "250 unidades.", "200 unidades.", "100 unidades.", "150 unidades."], "correct": 4, "c": "Ponto de pedido = (consumo médio × tempo de reposição) + estoque de segurança = (100 × 1) + 50 = 150. Ao atingir 150, dispara-se a compra. O PP sempre inclui o estoque de segurança."}, {"tema": "Gestão/Licitação", "q": "Para a aquisição de medicamentos comuns pela Administração Pública (Lei 14.133/2021), a modalidade preferencial é o", "ops": ["convite, para agilizar a compra.", "pregão, preferencialmente eletrônico, com critério de menor preço.", "leilão de bens.", "tomada de preços.", "concorrência, por ser a mais simples."], "correct": 1, "c": "Medicamentos são bens comuns → pregão eletrônico. Convite e tomada de preços foram extintos pela Lei 14.133/2021. Fornecedor único → inexigibilidade; compra parcelada → registro de preços."}, {"tema": "Gestão/Distribuição", "q": "O sistema de distribuição de medicamentos mais seguro em relação a erros e perdas é o de", "ops": ["distribuição por demanda verbal.", "estoque coletivo nas enfermarias.", "coletivo com reposição semanal.", "dose unitária.", "individualizado sem revisão farmacêutica."], "correct": 3, "c": "Segurança crescente: coletivo < individualizado < dose unitária. A dose unitária (doses prontas, identificadas por paciente, 24h) reduz erros e perdas e permite revisão farmacêutica completa."}, {"tema": "Portaria 344", "q": "Os medicamentos das listas A1, A2 (entorpecentes) e A3 (psicotrópicos) são dispensados mediante", "ops": ["Notificação de Receita 'B', de cor azul.", "Notificação de Receita 'A', de cor amarela.", "Receita de Controle Especial branca em 2 vias.", "receita médica comum, sem retenção.", "Notificação de Receita Especial branca."], "correct": 1, "c": "Lista A → Notificação de Receita Amarela (validade 30 dias, 30 dias de tratamento, 5 ampolas). É a única cuja numeração/talonário é fornecida pela vigilância sanitária."}, {"tema": "Portaria 344", "q": "Codeína e tramadol até 100 mg por unidade posológica, apesar de pertencerem à lista A2, são dispensados por", "ops": ["Receita de Controle Especial em 2 vias (branca).", "Notificação de Receita Especial branca.", "Notificação de Receita A (amarela).", "Notificação de Receita B (azul).", "receita médica comum, sem retenção."], "correct": 0, "c": "Adendo clássico: codeína e tramadol ≤100 mg (e oxicodona LC ≤40 mg) migram para a Receita de Controle Especial em 2 vias, apesar de serem lista A."}, {"tema": "Portaria 344", "q": "As substâncias da lista D1 (precursoras) são dispensadas mediante", "ops": ["Notificação de Receita Especial branca.", "receita médica comum, sem retenção, porém com escrituração.", "Receita de Controle Especial em 2 vias.", "Notificação de Receita A amarela.", "autorização do Ministério da Justiça para cada dispensação."], "correct": 1, "c": "A 'pegadinha do sem retenção': D1 é controlada, mas dispensada com receita comum, sem retenção (com escrituração). D2 (insumos químicos) fica sob o Ministério da Justiça/Polícia Federal (SIPROQUIM)."}, {"tema": "Portaria 344", "q": "A talidomida (lista C3), pelo histórico de teratogenicidade, caracteriza-se por", "ops": ["Notificação de Receita B azul.", "venda livre em drogarias.", "Notificação de Receita A amarela.", "dispensação por receita comum, em qualquer drogaria.", "Notificação de Receita Especial, com dispensação exclusiva em farmácias do serviço público."], "correct": 4, "c": "A talidomida usa Notificação de Receita Especial e dispensação restrita ao serviço público (RDC 11/2011 e 735/2022), com termo de responsabilidade, pelo histórico de focomelia."}, {"tema": "Portaria 344", "q": "Sobre a Notificação de Receita B (azul), é correto afirmar que", "ops": ["tem validade de 6 meses.", "destina-se a substâncias retinoicas.", "é de cor amarela e destina-se a entorpecentes.", "tem validade de 30 dias; a B1 permite até 60 dias e a B2 até 30 dias de tratamento.", "dispensa retenção na farmácia."], "correct": 3, "c": "NR-B (azul): B1 (psicotrópicos) e B2 (anorexígenos), validade 30 dias; tratamento de 60 dias na B1 e 30 na B2. Não confundir validade da notificação com tempo de tratamento."}, {"tema": "Portaria 344", "q": "Carbamazepina (lista C1), prescrita para epilepsia, pode constar na receita para tratamento de", "ops": ["até 6 meses (adendo dos anticonvulsivantes e antiparkinsonianos).", "até 90 dias.", "quantidade ilimitada.", "até 30 dias apenas.", "até 60 dias, como as demais C1."], "correct": 0, "c": "Adendo de ouro: anticonvulsivantes e antiparkinsonianos (C1) podem ser prescritos para até 6 meses de tratamento, sem justificativa. As demais C1/C5 ficam em 60 dias."}, {"tema": "Portaria 344", "q": "A escrituração eletrônica de medicamentos controlados e antimicrobianos nas farmácias é feita no", "ops": ["SIPROQUIM (para medicamentos).", "Notivisa.", "SISCONTROLE.", "VigiMed.", "SNGPC (Sistema Nacional de Gerenciamento de Produtos Controlados)."], "correct": 4, "c": "O SNGPC é o sistema de escrituração eletrônica de controlados e antimicrobianos. VigiMed = eventos adversos; Notivisa = queixas técnicas; SIPROQUIM = insumos químicos (Polícia Federal)."}, {"tema": "SNC/Benzodiazepínicos", "q": "O mecanismo de ação dos benzodiazepínicos consiste em", "ops": ["modular alostericamente o receptor GABA-A, aumentando a frequência de abertura do canal de cloro.", "bloquear canais de sódio dependentes de voltagem.", "agonizar o receptor NMDA.", "aumentar a duração de abertura do canal de cloro, como os barbitúricos.", "antagonizar o receptor GABA."], "correct": 0, "c": "Benzodiazepínicos aumentam a FREQUÊNCIA de abertura do canal de Cl⁻ (GABA-A); barbitúricos aumentam a DURAÇÃO (mais letais em overdose). Antídoto do BZD: flumazenil."}, {"tema": "SNC/Clozapina", "q": "A clozapina exige hemograma seriado pelo risco de", "ops": ["hepatotoxicidade.", "discinesia tardia.", "nefrotoxicidade.", "agranulocitose.", "síndrome de Stevens-Johnson."], "correct": 3, "c": "A clozapina (esquizofrenia refratária) exige monitorização por risco de agranulocitose (também miocardite, convulsão, sialorreia). Reduz suicídio. Parar de fumar eleva seu nível (perda da indução do 1A2)."}, {"tema": "SNC/Discinesia", "q": "A discinesia tardia associada ao uso prolongado de antipsicóticos típicos decorre de", "ops": ["hipersensibilidade (up-regulation) de receptores dopaminérgicos por bloqueio crônico.", "bloqueio agudo dos receptores D2.", "excitotoxicidade glutamatérgica.", "excesso de acetilcolina estriatal.", "bloqueio serotoninérgico."], "correct": 0, "c": "O bloqueio D2 crônico gera hipersensibilidade dos receptores → movimentos involuntários tardios, potencialmente irreversíveis. A distonia aguda (horas-dias) responde a anticolinérgico/biperideno."}, {"tema": "SNC/Parkinson", "q": "A carbidopa é associada à levodopa com o objetivo de", "ops": ["inibir a MAO-B.", "bloquear a enzima COMT.", "aumentar a conversão de levodopa em dopamina no SNC.", "inibir a dopa-descarboxilase periférica, elevando a levodopa que chega ao cérebro e reduzindo náuseas.", "antagonizar receptores dopaminérgicos periféricos."], "correct": 3, "c": "A carbidopa não cruza a barreira hematoencefálica e inibe a dopa-descarboxilase periférica → mais levodopa chega ao SNC, com menos náusea. Proteínas da dieta competem na absorção da levodopa."}, {"tema": "SNC/Opioides", "q": "A tríade clássica da intoxicação por opioides é composta por", "ops": ["rebaixamento do nível de consciência, depressão respiratória e miose puntiforme.", "bradicardia, hipotermia e rubor.", "midríase, taquicardia e hipertensão.", "convulsão, febre e rigidez muscular.", "hipertermia, clônus e agitação."], "correct": 0, "c": "Tríade opioide → antídoto naloxona. Hipertermia+clônus+agitação = síndrome serotoninérgica; febre+rigidez = síndrome neuroléptica maligna. Opioide + benzodiazepínico é a associação mais letal."}, {"tema": "SNC/Valproato", "q": "Sobre o ácido valproico, é correto afirmar que", "ops": ["é indicado exclusivamente para crises de ausência.", "não apresenta interação com outros anticonvulsivantes.", "é considerado seguro na gestação.", "é indutor enzimático potente do CYP450.", "é inibidor enzimático, eleva o nível de lamotrigina (risco de Stevens-Johnson) e é teratogênico."], "correct": 4, "c": "Ao contrário de fenitoína, carbamazepina e fenobarbital (indutores), o valproato é INIBIDOR → aumenta a lamotrigina (titular devagar, risco de SJS). É teratogênico (espinha bífida) e de amplo espectro. Lista C1."}, {"tema": "SNC/ISRS", "q": "A interação entre um ISRS (ex.: sertralina) e a linezolida pode desencadear", "ops": ["síndrome serotoninérgica, pois a linezolida tem atividade IMAO fraca.", "síndrome do homem vermelho.", "agranulocitose.", "rabdomiólise.", "crise hipertensiva por tiramina."], "correct": 0, "c": "A linezolida tem ação IMAO fraca; com ISRS pode causar síndrome serotoninérgica (alteração mental + hiperatividade autonômica + clônus). A síndrome do homem vermelho é da vancomicina."}, {"tema": "SNC/IMAO", "q": "Paciente em uso de IMAO que ingere queijos curados e vinho tinto e evolui com cefaleia intensa e crise hipertensiva apresenta", "ops": ["feocromocitoma.", "síndrome serotoninérgica.", "efeito dissulfiram.", "hipertensão essencial descompensada.", "a 'reação do queijo', por acúmulo de tiramina não degradada."], "correct": 4, "c": "O IMAO impede a degradação da tiramina dos alimentos fermentados → liberação de noradrenalina → crise hipertensiva ('reação do queijo'). Por isso a dieta restrita é mandatória."}, {"tema": "Erros/Definições", "q": "Um erro de medicação detectado e corrigido ANTES de atingir o paciente é classificado como", "ops": ["quase erro (near miss).", "circunstância de risco apenas.", "evento adverso.", "reação adversa a medicamento (RAM).", "incidente sem dano."], "correct": 0, "c": "Near miss = não atingiu o paciente; incidente sem dano = atingiu, mas sem lesão; evento adverso = atingiu e causou dano. RAM não é erro (é resposta em dose usual). Todos devem ser notificados."}, {"tema": "Erros/RAM×Erro", "q": "Um paciente faz anafilaxia a um antibiótico prescrito e administrado corretamente, sem alergia prévia conhecida. Trata-se de", "ops": ["uma incompatibilidade farmacêutica.", "um erro de dispensação.", "um erro de prescrição.", "uma reação adversa (RAM), não um erro de medicação, pois é evitável apenas em parte.", "um near miss."], "correct": 3, "c": "Erro é evitável; RAM (resposta nociva em dose usual) não é 'erro'. Conduta: tratar a reação e notificar farmacovigilância. A anafilaxia é RAM tipo B (imprevisível)."}, {"tema": "Erros/LASA", "q": "A troca de DOBUTAMINA por DOPAMINA, por nomes parecidos, é prevenida por estratégias como", "ops": ["uso exclusivo de abreviaturas.", "dispensação por demanda verbal.", "armazenamento conjunto para facilitar a comparação.", "tall man lettering (DOBUTamina × DOPAmina), separação física e alertas no sistema.", "prescrição manuscrita sem conferência."], "correct": 3, "c": "Erro LASA (look-alike, sound-alike): tall man lettering, separação física no estoque e alertas. São medicamentos de alta vigilância — exigem também dupla checagem."}, {"tema": "Erros/Reason", "q": "No modelo do 'queijo suíço' (James Reason), o foco da análise de um erro deve estar", "ops": ["no sistema e nas falhas latentes, e não na culpa individual.", "na punição do profissional que executou a ação.", "na demissão do responsável imediato.", "exclusivamente na falha ativa da ponta.", "na ocultação do erro para evitar processos."], "correct": 0, "c": "O acidente ocorre quando os 'buracos' das barreiras se alinham. Foco no sistema (falhas latentes/organizacionais), não na culpa. Cultura justa: pune-se a imprudência, não o erro honesto."}, {"tema": "Erros/Reason", "q": "No modelo de Reason, a falha na EXECUÇÃO de uma ação automática por distração (ex.: pegar o frasco errado sem perceber) é um", "ops": ["erro de conhecimento.", "lapso (falha de memória).", "deslize (slip).", "violação (desvio intencional de norma).", "engano (mistake, falha de planejamento)."], "correct": 2, "c": "Deslize/lapso = a ação não saiu como planejada (execução falha). Engano = o plano estava errado (planejamento). Violação = desvio intencional."}, {"tema": "Segurança/9 certos", "q": "Os '9 certos' da administração de medicamentos ampliam os 5 clássicos (paciente, medicamento, via, hora, dose) com", "ops": ["fabricante, lote, validade e temperatura certos.", "registro, orientação, forma e resposta certos.", "diluente, seringa, equipo e bomba certos.", "preço, embalagem, cor e sabor certos.", "prescritor, receita, carimbo e assinatura certos."], "correct": 1, "c": "Os 9 certos: paciente, medicamento, via, hora, dose (clássicos) + registro certo, orientação correta, forma certa e resposta/monitorização certa."}, {"tema": "Antimicrobianos/Dispensação", "q": "Segundo a RDC nº 471/2021, a prescrição de antimicrobianos deve ser feita em", "ops": ["Notificação de Receita A amarela.", "receita comum sem retenção.", "receituário com modelo oficial específico, em 3 vias.", "Notificação de Receita B azul.", "receituário comum (privativo do prescritor ou do estabelecimento), em 2 vias, com validade de 10 dias."], "correct": 4, "c": "A RDC 471/2021: receituário comum, 2 vias, validade 10 dias, aviada uma única vez; retém-se a 2ª via. Não há modelo oficial próprio (diferente das notificações da Portaria 344/98). Escrituração no SNGPC."}, {"tema": "Farmacovigilância/A-F", "q": "A falha contraceptiva causada pela rifampicina (indução enzimática) é classificada, na taxonomia de Rawlins & Thompson, como RAM do tipo", "ops": ["C (crônica).", "B (bizarra).", "F (failure / falha terapêutica).", "D (tardia).", "A (aumentada)."], "correct": 2, "c": "Tipo F = inefetividade inesperada (muitas vezes por interação/dose), como a falha do contraceptivo por rifampicina. É notificável."}, {"tema": "Farmacovigilância/A-F", "q": "A malformação por talidomida (focomelia), que se manifesta tempo após a exposição, é RAM do tipo", "ops": ["D (delayed / tardia).", "B (bizarra).", "A (aumentada).", "E (retirada).", "F (falha)."], "correct": 0, "c": "Tipo D (tardia) = teratogênese/carcinogênese, manifestada tempo depois. A talidomida é o marco histórico da farmacovigilância."}, {"tema": "Farmacovigilância/Causalidade", "q": "Na avaliação de causalidade de uma RAM, o critério de MAIOR peso é", "ops": ["a via de administração.", "a gravidade do evento.", "o rechallenge positivo (reaparecimento do evento ao reexpor o paciente ao fármaco).", "a idade do paciente.", "a relação temporal apenas."], "correct": 2, "c": "Dechallenge positivo (melhora ao retirar) + rechallenge positivo (volta ao reexpor) = nexo forte. O rechallenge positivo é o critério de maior peso. Algoritmo de Naranjo pontua a probabilidade."}, {"tema": "Interações/Quelação", "q": "A orientação de não tomar tetraciclinas ou quinolonas junto com leite, antiácidos ou ferro deve-se a", "ops": ["antagonismo no receptor bacteriano.", "quelação com cátions (Ca, Mg, Al, Fe), que reduz a absorção do antibiótico.", "aumento do pH gástrico que ativa o fármaco.", "indução enzimática que reduz o antibiótico.", "efeito dissulfiram."], "correct": 1, "c": "Tetraciclinas/quinolonas/bifosfonatos/levotiroxina formam complexos com cátions divalentes/trivalentes → ↓ absorção. Separar a administração por 2–4 horas."}, {"tema": "Interações/Tabagismo", "q": "Um paciente esquizofrênico estável em uso de clozapina é internado e para de fumar abruptamente. Espera-se", "ops": ["queda do nível de clozapina.", "nenhuma alteração de nível.", "indução adicional do metabolismo.", "aumento do nível de clozapina e risco de toxicidade, pela perda da indução do CYP1A2.", "síndrome de abstinência da clozapina."], "correct": 3, "c": "A fumaça induz o CYP1A2; ao cessar, a enzima reduz e a clozapina sobe → toxicidade (também teofilina e olanzapina). Requer ajuste de dose."}, {"tema": "Interações/Serotonina", "q": "A síndrome serotoninérgica é um risco ao associar", "ops": ["ISRS, IMAO, tramadol, triptanos e linezolida (fármacos serotoninérgicos).", "varfarina com vitamina K.", "betabloqueador com verapamil.", "digoxina com furosemida.", "ISRS com omeprazol."], "correct": 0, "c": "Excesso serotoninérgico (interação farmacodinâmica) → agitação, hipertermia, clônus. Cuidado ao somar ISRS/IRSN + IMAO + tramadol + triptanos + linezolida."}, {"tema": "SUS/Financiamento", "q": "Segundo a LC nº 141/2012, os percentuais mínimos de aplicação em ações e serviços de saúde são", "ops": ["municípios 12% e estados 15%.", "municípios e estados 10% cada.", "municípios 15% e estados 12% das receitas de impostos e transferências.", "municípios 20% e estados 12%.", "União 15% da receita corrente líquida, sem regra para estados."], "correct": 2, "c": "LC 141/2012: municípios ≥15% e estados ≥12% das receitas de impostos; a União segue regra própria. Gestão pelos Fundos de Saúde, com fiscalização dos Conselhos."}, {"tema": "SUS/Comissões", "q": "As instâncias de pactuação consensual entre os gestores nas três esferas são, respectivamente,", "ops": ["CONASS, CONASEMS e CNS.", "Conselho, Conferência e Ouvidoria.", "CIT (nacional), CIB (estadual) e CIR (regional).", "FNS, FES e FMS.", "CIT, CNS e CIB."], "correct": 2, "c": "Comissões intergestores: CIT (Tripartite, nacional), CIB (Bipartite, estadual) e CIR (Regional, do Decreto 7.508). Pactuação entre gestores ≠ deliberação do conselho (controle social)."}, {"tema": "SUS/Setor privado", "q": "Segundo a CF/88, a participação do setor privado no SUS ocorre de forma", "ops": ["complementar, com preferência às entidades filantrópicas e sem fins lucrativos.", "exclusiva para hospitais universitários privados.", "vedada em qualquer hipótese.", "direta, com destinação de recursos públicos a instituições com fins lucrativos.", "principal, substituindo a rede pública."], "correct": 0, "c": "A assistência é livre à iniciativa privada, que participa do SUS de forma complementar (contrato/convênio), com preferência a filantrópicas/sem fins lucrativos. Vedado lucro com recurso público."}, {"tema": "SUS/Vigilância sanitária", "q": "A vigilância sanitária, coordenada nacionalmente pela ANVISA, atua sobre", "ops": ["somente a qualidade da água e do ar.", "apenas a mortalidade e a natalidade.", "exclusivamente acidentes de trabalho.", "apenas a notificação de doenças transmissíveis.", "riscos decorrentes de produtos, serviços e ambientes de interesse da saúde."], "correct": 4, "c": "A VISA é a vigilância do 'risco antes do dano': produtos, serviços e ambientes (medicamentos, alimentos, serviços de saúde, portos/aeroportos). Para o farmacêutico, elo com RDCs e farmacovigilância."}, {"tema": "Gestão/Inexigibilidade", "q": "A aquisição de um medicamento de marca única, protegido por patente, com fornecedor exclusivo, é feita por", "ops": ["dispensa por emergência.", "concorrência pública.", "leilão.", "pregão eletrônico.", "inexigibilidade de licitação (inviabilidade de competição)."], "correct": 4, "c": "Fornecedor exclusivo → inexigibilidade (Lei 14.133/2021), com justificativa. Dispensa = valor baixo/emergência; pregão = bens comuns; registro de preços = compras parceladas."}, {"tema": "Gestão/EMTN", "q": "A Equipe Multiprofissional de Terapia Nutricional (EMTN) é obrigatória e composta, no mínimo, por", "ops": ["médico, nutricionista, farmacêutico e enfermeiro.", "apenas médico e nutricionista.", "nutricionista e técnico de nutrição.", "farmacêutico e enfermeiro somente.", "médico, enfermeiro e fisioterapeuta."], "correct": 0, "c": "A EMTN obrigatória: médico, nutricionista, farmacêutico e enfermeiro, habilitados e treinados. O farmacêutico manipula a nutrição parenteral e controla estabilidade/compatibilidade."}, {"tema": "Oncologia/Dose", "q": "A carboplatina, diferentemente da maioria dos quimioterápicos, é dosada por", "ops": ["nível sérico de creatinina isolado.", "superfície corporal (m²), como os demais.", "AUC (área sob a curva), pela fórmula de Calvert, considerando a função renal.", "idade do paciente.", "peso corporal em kg fixo."], "correct": 2, "c": "A maioria dos citotóxicos é dosada por superfície corporal (m²); a carboplatina é a exceção clássica — por AUC (fórmula de Calvert), que considera o clearance renal."}, {"tema": "Oncologia/Neutropenia", "q": "Paciente no 10º dia pós-quimioterapia chega com febre e neutrófilos muito baixos. A conduta é", "ops": ["suspender qualquer suporte e observar.", "aguardar a cultura antes de iniciar antibiótico.", "iniciar antifúngico isolado como primeira medida.", "administrar antitérmico e liberar para casa.", "antibioticoterapia empírica de amplo espectro imediata, pois a neutropenia febril é emergência oncológica."], "correct": 4, "c": "Neutropenia febril (nadir medular ~7–14 dias) é emergência: ATB empírico de amplo espectro imediato + suporte; G-CSF (filgrastim) conforme indicação."}, {"tema": "Interações/Deslocamento", "q": "O deslocamento de um fármaco de sua ligação proteica só costuma ter relevância clínica quando envolve fármacos", "ops": ["isentos de metabolismo hepático.", "administrados por via inalatória.", "hidrossolúveis de amplo índice terapêutico.", "de eliminação exclusivamente renal.", "muito ligados a proteínas, com baixo volume de distribuição e índice terapêutico estreito (ex.: varfarina, fenitoína)."], "correct": 4, "c": "O deslocamento proteico isolado raramente é relevante (o organismo compensa) — exceto em fármacos muito ligados, com baixo Vd e IT estreito (varfarina, fenitoína)."}, {"tema": "Monitorização/Ataque×Manutenção", "q": "No ajuste de doses, a dose de ATAQUE depende do volume de distribuição, enquanto a de MANUTENÇÃO depende", "ops": ["da idade isolada do paciente.", "do clearance (depuração), sendo reduzida na insuficiência renal para fármacos de eliminação renal.", "apenas do peso corporal.", "também do volume de distribuição, igualmente.", "da via de administração apenas."], "correct": 1, "c": "Ataque 'enche o tanque' (Vd) e independe da função renal; manutenção 'repõe o que sai' (clearance) e deve ser ajustada na IRC (digoxina, lítio, aminoglicosídeo, vancomicina)."}, {"tema": "Antimicrobianos/VRE", "q": "Diante de um Enterococcus resistente à vancomicina (VRE) em hemocultura, uma opção terapêutica é", "ops": ["amoxicilina isolada.", "meropenem.", "ceftriaxona.", "linezolida (ou daptomicina).", "azitromicina."], "correct": 3, "c": "VRE → linezolida ou daptomicina, com precaução de contato. ESBL → carbapenêmico; MRSA → vancomicina; KPC → polimixina/ceftazidima-avibactam."}, {"tema": "Nutrição/Enteral", "q": "Para prevenir broncoaspiração durante a nutrição enteral, recomenda-se manter a cabeceira elevada a", "ops": ["10 graus.", "0 grau (decúbito horizontal).", "30–45 graus.", "90 graus, sentado ereto contínuo.", "posição de Trendelenburg."], "correct": 2, "c": "Manter cabeceira a 30–45° reduz o risco de broncoaspiração na nutrição enteral. Complicações também incluem diarreia, distensão e deslocamento/obstrução da sonda."}, {"tema": "Farmacoepidemiologia/NNT", "q": "Em um ensaio, o risco de evento no controle é 20% e no tratado 15%. O NNT (número necessário para tratar) é", "ops": ["5.", "100.", "10.", "15.", "20 (NNT = 1 ÷ RAR = 1 ÷ 0,05)."], "correct": 4, "c": "RAR = 0,20 − 0,15 = 0,05; NNT = 1/RAR = 1/0,05 = 20 → tratar 20 pacientes para evitar 1 evento. Quanto menor o NNT, mais eficaz. A RRR (25%) 'parece' maior, mas olhe o risco absoluto."}, {"tema": "Farmacoepidemiologia/Fases", "q": "A farmacovigilância corresponde principalmente à fase", "ops": ["pré-clínica (in vitro e animais).", "III (grandes ensaios para registro).", "IV (pós-comercialização), que monitora segurança e efetividade em uso real e em larga escala.", "I (voluntários sadios).", "II (eficácia/dose em pacientes)."], "correct": 2, "c": "F1 sadios (segurança/PK) · F2 pacientes (eficácia/dose) · F3 grande ECR (registro) · F4 farmacovigilância (pós-mercado, detecta RAM raras/tardias)."}, {"tema": "SUS/Indígena", "q": "A Lei Arouca (Lei 9.836/1999) criou, dentro do SUS,", "ops": ["a Política Nacional de Saúde da População Negra.", "o Subsistema de Atenção à Saúde Indígena, gerido pela SESAI e organizado em DSEIs.", "a Rede Cegonha.", "o Consultório na Rua.", "o Programa Nacional de Imunizações."], "correct": 1, "c": "Lei Arouca (9.836/1999) → Subsistema de Atenção à Saúde Indígena, regido pela PNASPI, gerido pela SESAI (Ministério da Saúde) por meio de Distritos Sanitários Especiais Indígenas (DSEI)."}, {"tema": "SUS/Redes temáticas", "q": "A antiga Rede Cegonha (saúde materno-infantil) foi reestruturada e renomeada em 2024 para", "ops": ["Rede Alyne, com foco em reduzir a mortalidade materna, sobretudo de mulheres negras.", "Rede de Doenças Crônicas.", "Rede de Atenção às Urgências (RUE).", "Rede de Atenção Psicossocial (RAPS).", "Rede Viver sem Limite."], "correct": 0, "c": "A Rede Cegonha foi renomeada Rede Alyne (Portaria 5.350/2024), homenageando Alyne Pimentel, com foco na mortalidade materna, especialmente de mulheres negras."}, {"tema": "Antimicrobianos/Sulfa", "q": "A combinação sulfametoxazol-trimetoprima é bactericida porque", "ops": ["bloqueia sequencialmente dois pontos da via do folato (di-hidropteroato-sintetase e di-hidrofolato-redutase).", "rompe a membrana celular.", "inibe a DNA-girase.", "inibe a subunidade 50S do ribossomo.", "atua na parede celular como os β-lactâmicos."], "correct": 0, "c": "Sulfa inibe a di-hidropteroato-sintetase (análogo do PABA) e a trimetoprima a di-hidrofolato-redutase → bloqueio sequencial da via do folato (sinergia bactericida). Cobre PCP, MRSA comunitário, Nocardia."}, {"tema": "Interações/Metotrexato", "q": "A associação de metotrexato com AINEs ou sulfametoxazol-trimetoprima aumenta o risco de", "ops": ["falha terapêutica do metotrexato por indução enzimática.", "rabdomiólise.", "efeito dissulfiram.", "toxicidade do metotrexato, por redução de sua excreção renal.", "crise hipertensiva."], "correct": 3, "c": "AINEs, probenecida e SMX-TMP reduzem a excreção renal do metotrexato → toxicidade (mielo/nefro/mucosite). Monitorar níveis e função renal; resgatar com leucovorin."}, {"tema": "Gestão/Cadeia de frio", "q": "No armazenamento de vacinas e insulina (termolábeis), o cuidado crítico é", "ops": ["manter à temperatura ambiente, ao abrigo da luz.", "manter entre 2 e 8 °C, com monitoramento contínuo de temperatura (cadeia de frio).", "congelar a −20 °C para maior durabilidade.", "refrigerar apenas durante o transporte.", "manter entre 15 e 30 °C."], "correct": 1, "c": "Termolábeis (vacinas, insulina, alguns biológicos) exigem cadeia de frio 2–8 °C com monitoramento; a quebra da cadeia inutiliza o produto. Congelar pode inativar vacinas/insulina."}, {"tema": "Antimicrobianos/Metronidazol", "q": "O metronidazol tem espectro voltado principalmente a", "ops": ["anaeróbios (abaixo do diafragma) e protozoários (Giardia, Entamoeba, Trichomonas).", "atípicos (Chlamydia, Mycoplasma).", "Gram-positivos aeróbios apenas.", "fungos filamentosos.", "Pseudomonas e Acinetobacter."], "correct": 0, "c": "Metronidazol: anaeróbios, protozoários, C. difficile e esquema de H. pylori. Em meio anaeróbio é reduzido a radicais que fragmentam o DNA. Efeito dissulfiram com álcool."}, {"tema": "Antimicrobianos/Rifampicina", "q": "A rifampicina, usada em micobactérias, deve ser sempre usada em associação porque", "ops": ["não penetra em biofilmes.", "é bacteriostática isolada.", "tem meia-vida muito curta.", "é inativada pelo suco gástrico.", "a resistência (mutação rpoB) surge rapidamente em monoterapia."], "correct": 4, "c": "A rifampicina (inibe a RNA-polimerase) seleciona resistência rápida por mutação rpoB em monoterapia → usar sempre em associação. É indutor potente do CYP450."}, {"tema": "SUS/Consultório na Rua", "q": "O Consultório na Rua (eCR), da Atenção Básica, caracteriza-se por", "ops": ["ser um local fixo de atendimento exclusivo.", "ser uma equipe itinerante que leva o cuidado à população em situação de rua, sem exigir comprovante de residência.", "atuar apenas em urgências hospitalares.", "condicionar o atendimento à apresentação de documento.", "substituir as Unidades Básicas de Saúde."], "correct": 1, "c": "O Consultório na Rua é uma equipe da Atenção Básica (não um local fixo); o acesso não pode ser condicionado a endereço/documento. Articula-se com UBS, CAPS e RUE."}, {"tema": "SUS/ACS×ACE", "q": "A diferença entre o Agente Comunitário de Saúde (ACS) e o Agente de Combate às Endemias (ACE) é que", "ops": ["o ACE integra a eSF e o ACS não.", "ambos exercem a mesma função na vigilância sanitária.", "o ACS combate endemias e o ACE faz visitas domiciliares.", "ambos são regulamentados por leis distintas.", "o ACS é o elo entre a comunidade e a eSF e reside na área, enquanto o ACE atua na vigilância/controle de vetores."], "correct": 4, "c": "ACS (ligado à eSF, mora na área, cadastramento/visitas) × ACE (vigilância, controle do Aedes). Ambos regulamentados pela Lei 11.350/2006."}, {"tema": "Bioética/Autonomia", "q": "O Termo de Consentimento Livre e Esclarecido (TCLE) é a expressão prática do princípio da", "ops": ["integralidade.", "beneficência.", "não maleficência.", "autonomia.", "justiça."], "correct": 3, "c": "A autonomia (autodeterminação) sustenta o consentimento livre e esclarecido, obtido antes da participação, sem coação e em linguagem acessível."}, {"tema": "Farmacovigilância/Gravidade", "q": "Considera-se RAM grave/séria aquela que resulta em", "ops": ["qualquer sintoma intenso relatado pelo paciente.", "interação medicamentosa teórica.", "necessidade de ajuste de dose apenas.", "reação restrita à pele sem outras repercussões.", "óbito, ameaça à vida, hospitalização, incapacidade persistente ou anomalia congênita."], "correct": 4, "c": "Gravidade é definida pelo DESFECHO (mnemônico MAHIA: Morte, Ameaça à vida, Hospitalização, Incapacidade, Anomalia congênita), não pela intensidade do sintoma."}, {"tema": "Oncologia/Ciclo celular", "q": "Os agentes alquilantes (ex.: ciclofosfamida) são classificados quanto ao ciclo celular como", "ops": ["ativos apenas na mitose.", "ciclo-específicos da fase S.", "ciclo-inespecíficos (atuam em qualquer fase, inclusive G0).", "ciclo-específicos da fase M.", "ativos apenas na fase G1."], "correct": 2, "c": "Alquilantes, platinas e antraciclinas = ciclo-inespecíficos. Antimetabólitos = fase S; vinca e taxanos = fase M (vinca despolimeriza, taxano estabiliza microtúbulos)."}, {"tema": "Antimicrobianos/Macrolídeo×inibição", "q": "Entre os macrolídeos, o que NÃO inibe significativamente o CYP450 (pegadinha de interações) é a", "ops": ["claritromicina.", "azitromicina.", "claritromicina e eritromicina.", "eritromicina.", "nenhum deles."], "correct": 1, "c": "Claritromicina e eritromicina inibem o CYP3A4; a azitromicina praticamente não inibe — 'pegadinha' clássica em questões de interação."}, {"tema": "Monitorização/Amino", "q": "No esquema convencional de aminoglicosídeos, um vale acima do alvo (< 2 µg/mL) indica", "ops": ["eficácia adequada, sem necessidade de ajuste.", "erro laboratorial, devendo ser ignorado.", "necessidade de reduzir o intervalo entre doses.", "subdose, exigindo aumento imediato da dose.", "acúmulo e risco de nefro/ototoxicidade, exigindo prolongar o intervalo entre doses."], "correct": 4, "c": "Vale alto de aminoglicosídeo/vancomicina = risco de toxicidade (acúmulo), não de eficácia. A eficácia do aminoglicosídeo depende do PICO. Conduta: prolongar o intervalo (e/ou reduzir a dose)."}, {"tema": "SUS/RENASES×RENAME", "q": "No Decreto 7.508/2011, a relação que reúne todas as AÇÕES E SERVIÇOS oferecidos pelo SUS é a", "ops": ["RENAST (saúde do trabalhador).", "RENAME (medicamentos essenciais).", "COAP (contrato interfederativo).", "RENASES (Relação Nacional de Ações e Serviços de Saúde).", "RAS (Rede de Atenção à Saúde)."], "correct": 3, "c": "RENASES = ações e serviços; RENAME = medicamentos essenciais. Não trocar as duas. A APS é a porta de entrada preferencial/ordenadora da rede."}, {"tema": "Interações/Antagonismo", "q": "A redução do efeito anti-hipertensivo de IECA e diuréticos causada pelos AINEs ocorre por", "ops": ["retenção de sódio e inibição de prostaglandinas renais (antagonismo farmacodinâmico).", "quelação intestinal do anti-hipertensivo.", "deslocamento da ligação proteica.", "indução do metabolismo do anti-hipertensivo.", "aumento da excreção renal do anti-hipertensivo."], "correct": 0, "c": "AINEs retêm sódio/água e inibem prostaglandinas renais → reduzem a eficácia de anti-hipertensivos e diuréticos e pioram a função renal ('triple whammy': IECA + diurético + AINE)."}, {"tema": "Segurança/Ordem verbal", "q": "No protocolo de segurança, a ordem verbal de medicação é admitida", "ops": ["rotineiramente, para agilizar o atendimento.", "em qualquer situação, desde que anotada depois.", "somente para medicamentos de baixa vigilância.", "sem necessidade de confirmação, se o médico for conhecido.", "apenas em emergência, com repetição pelo receptor (read-back), confirmação e registro posterior."], "correct": 4, "c": "Ordem verbal só em emergência, com 'ler de volta' (read-back), confirmação do prescritor e registro escrito assim que possível. Fora disso, exige-se prescrição escrita."}];
